import{_ as e,a,b as d,c as r,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as l,o as i,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const T=JSON.parse('{"title":"إضافة قناة Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/telegram.md","filePath":"ar-SA/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"ar-SA/upload/telegram.md"};function c(p,t,m,g,b,u){return i(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="إضافة-قناة-telegram" tabindex="-1">إضافة قناة Telegram <a class="header-anchor" href="#إضافة-قناة-telegram" aria-label="Permalink to &quot;إضافة قناة Telegram&quot;">​</a></h1><h2 id="ما-الذي-تحتاجه-قبل-البدء؟" tabindex="-1">ما الذي تحتاجه قبل البدء؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-قبل-البدء؟" aria-label="Permalink to &quot;ما الذي تحتاجه قبل البدء؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المتطلب</th><th>الغرض</th></tr></thead><tbody><tr><td>حساب Telegram</td><td>لإنشاء البوت وقناة التخزين.</td></tr><tr><td><code>@BotFather</code></td><td>لإنشاء بوت Telegram.</td></tr><tr><td>قناة Telegram</td><td>الوجهة النهائية التي تُحفظ فيها الملفات.</td></tr><tr><td><code>@userinfobot</code></td><td>لمعرفة <code>Chat ID</code> الخاص بالقناة.</td></tr></tbody></table><h2 id="أين-تضيفها؟" tabindex="-1">أين تضيفها؟ <a class="header-anchor" href="#أين-تضيفها؟" aria-label="Permalink to &quot;أين تضيفها؟&quot;">​</a></h2><ol><li>افتح إعدادات النظام.</li><li>انتقل إلى إعدادات الرفع.</li><li>اضغط Add Channel في الزاوية العلوية اليمنى.</li><li>اختر <code>Telegram</code>.</li></ol><h2 id="شرح-الحقول" tabindex="-1">شرح الحقول <a class="header-anchor" href="#شرح-الحقول" aria-label="Permalink to &quot;شرح الحقول&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الحقل</th><th>وظيفته</th><th>مطلوب</th></tr></thead><tbody><tr><td>اسم القناة</td><td>اسم واضح للقناة، مثل &quot;Telegram Primary&quot;.</td><td>نعم</td></tr><tr><td>Active</td><td>تفعيل القناة أو تعطيلها.</td><td>موصى به</td></tr><tr><td>Bot Token</td><td>رمز بوت Telegram.</td><td>نعم</td></tr><tr><td>Session ID (Chat ID)</td><td>معرّف قناة Telegram.</td><td>نعم</td></tr><tr><td>Relay Proxy URL (اختياري)</td><td>استخدمه فقط إذا كان الوصول إلى Telegram غير مستقر. أدخل الرابط كاملًا مع <code>https://</code>.</td><td>لا</td></tr><tr><td>Remark</td><td>ملاحظات للصيانة لاحقًا.</td><td>لا</td></tr></tbody></table><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><h3 id="_1-أنشئ-بوت-telegram" tabindex="-1">1. أنشئ بوت Telegram <a class="header-anchor" href="#_1-أنشئ-بوت-telegram" aria-label="Permalink to &quot;1. أنشئ بوت Telegram&quot;">​</a></h3><ol><li>افتح Telegram وابحث عن <code>@BotFather</code>.</li><li>افتح المحادثة واضغط <code>Start</code>.</li><li>أرسل <code>/newbot</code>.</li><li>اتبع التعليمات لإدخال اسم عرض البوت.</li><li>اتبع التعليمات لإدخال اسم مستخدم البوت. غالبًا يجب أن ينتهي الاسم بـ <code>bot</code>.</li><li>بعد إنشاء البوت سيعيد <code>@BotFather</code> رمز البوت.</li></ol><p>هذا الرمز هو قيمة <code>Bot Token</code> التي تحتاج إلى إدخالها في ImgBed.</p><p><img src="'+e+'" alt="حفظ رمز البوت" loading="lazy"></p><h3 id="_2-أنشئ-قناة" tabindex="-1">2. أنشئ قناة <a class="header-anchor" href="#_2-أنشئ-قناة" aria-label="Permalink to &quot;2. أنشئ قناة&quot;">​</a></h3><ol><li>في Telegram اضغط New Channel.</li><li>أدخل اسم القناة.</li><li>أكمل إنشاء القناة.</li></ol><p>يمكن استخدام القنوات العامة أو الخاصة.</p><p><img src="'+a+'" alt="إنشاء قناة" loading="lazy"></p><h3 id="_3-أضف-البوت-إلى-القناة" tabindex="-1">3. أضف البوت إلى القناة <a class="header-anchor" href="#_3-أضف-البوت-إلى-القناة" aria-label="Permalink to &quot;3. أضف البوت إلى القناة&quot;">​</a></h3><ol><li>افتح القناة التي أنشأتها.</li><li>افتح إعدادات القناة.</li><li>أضف عضوًا أو مسؤولًا.</li><li>ابحث عن اسم مستخدم البوت الذي أنشأته.</li><li>أضف البوت إلى القناة.</li></ol><p>لرفع أكثر موثوقية، امنح البوت صلاحيات مسؤول.</p><p><img src="'+d+'" alt="دعوة البوت إلى القناة" loading="lazy"></p><h3 id="_4-احصل-على-معرّف-القناة-عبر-user-info-get-id-idbot" tabindex="-1">4. احصل على معرّف القناة عبر User Info - Get ID - IDbot <a class="header-anchor" href="#_4-احصل-على-معرّف-القناة-عبر-user-info-get-id-idbot" aria-label="Permalink to &quot;4. احصل على معرّف القناة عبر User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>ابحث عن <code>@userinfobot</code> في Telegram. غالبًا يظهر باسم <code>User Info - Get ID - IDbot</code>.</li><li>افتح المحادثة واضغط <code>Start</code>.</li><li>اختر <code>Channel</code> من الخيارات التي يقدمها البوت.</li><li>من منتقي الرسائل اختر القناة المطلوبة وأرسلها إلى <code>@userinfobot</code>.</li><li>عندما يعرض <code>@userinfobot</code> النتيجة، انسخ الرقم الظاهر بصيغة <code>Id: -100...</code>.</li></ol><p>الرقم الذي يبدأ بـ <code>-100</code> هو قيمة <code>Session ID (Chat ID)</code> المطلوبة في ImgBed.</p><p><img src="'+r+'" alt="الحصول على معرف القناة" loading="lazy"></p><h3 id="_5-املأ-قناة-telegram-في-imgbed" tabindex="-1">5. املأ قناة Telegram في ImgBed <a class="header-anchor" href="#_5-املأ-قناة-telegram-في-imgbed" aria-label="Permalink to &quot;5. املأ قناة Telegram في ImgBed&quot;">​</a></h3><p>ارجع إلى نافذة إعداد القناة واملأ الحقول كما يلي:</p><table tabindex="0"><thead><tr><th>حقل الواجهة</th><th>القيمة</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>اسم مخصص للقناة، مثل <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>يُنصح بتفعيله.</td></tr><tr><td>Bot Token</td><td>رمز البوت من <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>الرقم <code>-100...</code> الذي أعاده <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (اختياري)</td><td>عند الحاجة فقط، مثل <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>ملاحظات اختيارية.</td></tr></tbody></table><p>بعد الانتهاء اضغط Save.</p><p><img src="'+o+`" alt="تعديل الإعداد" loading="lazy"></p><h2 id="كيف-تتحقق؟" tabindex="-1">كيف تتحقق؟ <a class="header-anchor" href="#كيف-تتحقق؟" aria-label="Permalink to &quot;كيف تتحقق؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الفحص</th><th>طريقة التحقق</th></tr></thead><tbody><tr><td>ظهور بطاقة القناة</td><td>بعد الحفظ يجب أن تظهر بطاقة قناة Telegram في صفحة إعدادات الرفع.</td></tr><tr><td>إمكانية تفعيل القناة</td><td>يجب أن يبقى مفتاح Active مفعّلًا.</td></tr><tr><td>حفظ الإعداد</td><td>يجب أن تظهر في التفاصيل قيم Bot Token و Chat ID محفوظة.</td></tr><tr><td>نجاح الرفع</td><td>ارفع صورة تجريبية وتأكد من ظهورها في قناة Telegram الهدف.</td></tr></tbody></table><h2 id="قائمة-تحقق-سريعة" tabindex="-1">قائمة تحقق سريعة <a class="header-anchor" href="#قائمة-تحقق-سريعة" aria-label="Permalink to &quot;قائمة تحقق سريعة&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>أنشئ بوتًا عبر @BotFather</span></span>
<span class="line"><span>-&gt; احفظ Bot Token</span></span>
<span class="line"><span>-&gt; أنشئ قناة Telegram</span></span>
<span class="line"><span>-&gt; أضف البوت إلى القناة وامنحه صلاحيات مسؤول</span></span>
<span class="line"><span>-&gt; ابحث عن @userinfobot واختر Channel</span></span>
<span class="line"><span>-&gt; أرسل أي رسالة من القناة إلى @userinfobot</span></span>
<span class="line"><span>-&gt; انسخ القيمة Id: -100...</span></span>
<span class="line"><span>-&gt; أدخل Bot Token و Chat ID في ImgBed</span></span>
<span class="line"><span>-&gt; احفظ وارفع صورة تجريبية</span></span></code></pre></div><h2 id="مراجع" tabindex="-1">مراجع <a class="header-anchor" href="#مراجع" aria-label="Permalink to &quot;مراجع&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const I=l(h,[["render",c]]);export{T as __pageData,I as default};
